import{_ as e,c as a,o,a1 as s}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Инициализация: сканирование проекта | opencode-supermemory","description":"Узнайте, как инициализировать проект. Команда /supermemory-init позволяет Agent просканировать код, извлечь архитектуру и сохранить в памяти.","frontmatter":{"title":"Инициализация: сканирование проекта | opencode-supermemory","sidebarTitle":"Инициализация","subtitle":"Инициализация: сканирование проекта","description":"Узнайте, как инициализировать проект. Команда /supermemory-init позволяет Agent просканировать код, извлечь архитектуру и сохранить в памяти.","tags":["Инициализация","Генерация памяти","Рабочий процесс"],"prerequisite":["start-getting-started"],"order":2},"headers":[],"relativePath":"ru/supermemoryai/opencode-supermemory/start/initialization/index.md","filePath":"ru/supermemoryai/opencode-supermemory/start/initialization/index.md"}'),i={name:"ru/supermemoryai/opencode-supermemory/start/initialization/index.md"};function r(n,t,l,d,c,p){return o(),a("div",null,[...t[0]||(t[0]=[s(`<h1 id="инициализация-проекта-создание-первого-впечатления" tabindex="-1">Инициализация проекта: создание первого впечатления <a class="header-anchor" href="#инициализация-проекта-создание-первого-впечатления" aria-label="Permalink to &quot;Инициализация проекта: создание первого впечатления&quot;">​</a></h1><h2 id="что-вы-сможете-сделать-после-изучения" tabindex="-1">Что вы сможете сделать после изучения <a class="header-anchor" href="#что-вы-сможете-сделать-после-изучения" aria-label="Permalink to &quot;Что вы сможете сделать после изучения&quot;">​</a></h2><ul><li><strong>Быстро ознакомиться с проектом</strong>: Позвольте Agent как новому сотруднику активно изучать и понимать всю кодовую базу.</li><li><strong>Создать долгосрочную память</strong>: Автоматически извлечь технологический стек, архитектурные шаблоны и стандарты кодирования проекта и сохранить в Supermemory.</li><li><strong>Устранить повторные объяснения</strong>: Больше не нужно повторять &quot;мы используем Bun&quot; или &quot;все компоненты должны быть протестированы&quot; в начале каждой сессии.</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Сталкивались ли вы с этими ситуациями:</p><ul><li><strong>Повторяющаяся работа</strong>: В каждой новой сессии нужно много рассказывать Agent о базовой информации проекта.</li><li><strong>Забывание контекста</strong>: Agent часто забывает специфичную структуру каталогов проекта и создает файлы в неправильных местах.</li><li><strong>Несогласованные стандарты</strong>: Стиль кода, который пишет Agent, нестабилен — то использует <code>interface</code>, то <code>type</code>.</li></ul><h2 id="когда-использовать-этот-метод" tabindex="-1">Когда использовать этот метод <a class="header-anchor" href="#когда-использовать-этот-метод" aria-label="Permalink to &quot;Когда использовать этот метод&quot;">​</a></h2><ul><li><strong>После установки плагина</strong>: Это первый шаг использования opencode-supermemory.</li><li><strong>При принятии нового проекта</strong>: Быстро создать базу памяти для этого проекта.</li><li><strong>После значительного рефакторинга</strong>: Когда архитектура проекта изменяется, нужно обновить знания Agent.</li></ul><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Предварительная проверка</p><p>Убедитесь, что вы выполнили шаги установки и настройки из <a href="./../getting-started/">Быстрый старт</a> и <code>SUPERMEMORY_API_KEY</code> правильно настроен.</p></div><h2 id="основная-идея" tabindex="-1">Основная идея <a class="header-anchor" href="#основная-идея" aria-label="Permalink to &quot;Основная идея&quot;">​</a></h2><p>Команда <code>/supermemory-init</code> по сути не является двоичной программой, а <strong>тщательно разработанным Prompt</strong> (подсказкой).</p><p>Когда вы запускаете эту команду, она отправляет Agent подробное &quot;руководство для новых сотрудников&quot;, указывающее Agent:</p><ol><li><strong>Глубокое исследование</strong>: Активно читать <code>README.md</code>, <code>package.json</code>, записи коммитов Git и т. д.</li><li><strong>Структурный анализ</strong>: Определять технологический стек, архитектурные шаблоны, неявные соглашения проекта.</li><li><strong>Постоянное хранение</strong>: Использовать инструмент <code>supermemory</code> для сохранения этих знаний в облачной базе данных.</li></ol><div class="info custom-block"><p class="custom-block-title">Область действия памяти</p><p>Процесс инициализации различает два типа памяти:</p><ul><li><strong>Project Scope</strong>: Действует только для текущего проекта (например: команды сборки, структура каталогов).</li><li><strong>User Scope</strong>: Действует для всех ваших проектов (например: предпочитаемый стиль кодирования).</li></ul></div><h2 id="следуите-моему-примеру" tabindex="-1">Следуйте моему примеру <a class="header-anchor" href="#следуите-моему-примеру" aria-label="Permalink to &quot;Следуйте моему примеру&quot;">​</a></h2><h3 id="шаг-1-запуск-команды-инициализации" tabindex="-1">Шаг 1: Запуск команды инициализации <a class="header-anchor" href="#шаг-1-запуск-команды-инициализации" aria-label="Permalink to &quot;Шаг 1: Запуск команды инициализации&quot;">​</a></h3><p>В поле ввода OpenCode введите следующую команду и отправьте:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/supermemory-init</span></span></code></pre></div><p><strong>Почему</strong> Это загрузит предопределенный Prompt и запустит режим исследования Agent.</p><p><strong>Что вы должны увидеть</strong> Agent начинает отвечать, указывая, что он понимает задачу и начинает планировать шаги исследования. Он может сказать: &quot;I will start by exploring the codebase structure and configuration files...&quot;</p><h3 id="шаг-2-наблюдение-за-процессом-исследования-agent" tabindex="-1">Шаг 2: Наблюдение за процессом исследования Agent <a class="header-anchor" href="#шаг-2-наблюдение-за-процессом-исследования-agent" aria-label="Permalink to &quot;Шаг 2: Наблюдение за процессом исследования Agent&quot;">​</a></h3><p>Agent автоматически выполнит серию операций, вам просто нужно смотреть. Обычно он:</p><ol><li><strong>Чтение файлов конфигурации</strong>: Читает <code>package.json</code>, <code>tsconfig.json</code> и т. д., чтобы понять технологический стек.</li><li><strong>Просмотр истории Git</strong>: Запускает <code>git log</code>, чтобы понять стандарты коммитов и активных участников.</li><li><strong>Исследование структуры каталогов</strong>: Использует <code>ls</code> или <code>list_files</code> для просмотра макета проекта.</li></ol><p><strong>Пример вывода</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Agent] Reading package.json to identify dependencies...</span></span>
<span class="line"><span>[Agent] Running git log to understand commit conventions...</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Совет по потреблению</p><p>Этот процесс представляет собой глубокое исследование, которое может потребовать много токенов (обычно выполняется 50+ вызовов инструментов). Пожалуйста, подождите, пока Agent сообщит о завершении.</p></div><h3 id="шаг-3-проверка-сгенерированнои-памяти" tabindex="-1">Шаг 3: Проверка сгенерированной памяти <a class="header-anchor" href="#шаг-3-проверка-сгенерированнои-памяти" aria-label="Permalink to &quot;Шаг 3: Проверка сгенерированной памяти&quot;">​</a></h3><p>Когда Agent сообщает, что инициализация завершена, вы можете проверить, что именно он запомнил. Введите:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/ask</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Список</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> памяти</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> текущего</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> проекта</span></span></code></pre></div><p>Или напрямую вызовите инструмент (если вы хотите просмотреть исходные данные):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>supermemory(mode: &quot;list&quot;, scope: &quot;project&quot;)</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong> Agent перечисляет серию структурированной памяти, например:</p><table tabindex="0"><thead><tr><th>Тип</th><th>Пример содержимого</th></tr></thead><tbody><tr><td><code>project-config</code></td><td>&quot;Использует Bun runtime. Команда сборки: bun run build&quot;</td></tr><tr><td><code>architecture</code></td><td>&quot;Маршруты API находятся в src/routes/, используется фреймворк Hono&quot;</td></tr><tr><td><code>preference</code></td><td>&quot;Строгое использование TypeScript: тип &#39;any&#39; не разрешен&quot;</td></tr></tbody></table><h3 id="шаг-4-добавление-пропущенного-по-желанию" tabindex="-1">Шаг 4: Добавление пропущенного (по желанию) <a class="header-anchor" href="#шаг-4-добавление-пропущенного-по-желанию" aria-label="Permalink to &quot;Шаг 4: Добавление пропущенного (по желанию)&quot;">​</a></h3><p>Если Agent пропустил определенную ключевую информацию (например, определенное специальное правило, которое только устно согласовано), вы можете вручную добавить:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Запомните: в этом проекте вся обработка дат должна использовать библиотеку dayjs, использование нативного Date запрещено.</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong> Agent отвечает подтверждением и вызывает <code>supermemory(mode: &quot;add&quot;)</code> для сохранения этого нового правила.</p><h2 id="контрольная-точка-✅" tabindex="-1">Контрольная точка ✅ <a class="header-anchor" href="#контрольная-точка-✅" aria-label="Permalink to &quot;Контрольная точка ✅&quot;">​</a></h2><ul><li>[ ] После запуска <code>/supermemory-init</code> Agent автоматически выполняет задачи исследования?</li><li>[ ] Можно ли просмотреть новую память с помощью команды <code>list</code>?</li><li>[ ] Точно ли содержимое памяти отражает фактическую ситуацию текущего проекта?</li></ul><h2 id="предупреждения-о-типичных-ошибках" tabindex="-1">Предупреждения о типичных ошибках <a class="header-anchor" href="#предупреждения-о-типичных-ошибках" aria-label="Permalink to &quot;Предупреждения о типичных ошибках&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Не запускайте часто</p><p>Инициализация — это длительный и затратный по токенам процесс. Обычно для каждого проекта нужно запустить только один раз. Пересоздание нужно только тогда, когда в проекте происходят значительные изменения.</p></div><div class="danger custom-block"><p class="custom-block-title">Внимание к конфиденциальности</p><p>Хотя плагин автоматически удаляет чувствительные данные в тегах <code>&lt;private&gt;</code>, во время инициализации Agent читает множество файлов. Убедитесь, что в вашей кодовой базе нет жестко закодированных чувствительных ключей (например, AWS Secret Key), иначе они могут быть сохранены в памяти как &quot;конфигурация проекта&quot;.</p></div><h2 id="итог-урока" tabindex="-1">Итог урока <a class="header-anchor" href="#итог-урока" aria-label="Permalink to &quot;Итог урока&quot;">​</a></h2><p>С помощью <code>/supermemory-init</code> мы завершили переход от &quot;незнакомца&quot; к &quot;опытному сотруднику&quot;. Теперь Agent запомнил основную архитектуру и стандарты проекта, и в следующих задачах кодирования он автоматически будет использовать этот контекст, чтобы предоставлять более точную помощь.</p><h2 id="предпросмотр-следующего-урока" tabindex="-1">Предпросмотр следующего урока <a class="header-anchor" href="#предпросмотр-следующего-урока" aria-label="Permalink to &quot;Предпросмотр следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../../core/context-injection/">Механизм автоматического внедрения контекста</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как Agent &quot;вспоминает&quot; эту память в начале сессии.</li><li>Как с помощью ключевых слов триггерировать вызов определенной памяти.</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы просмотреть расположение исходного кода</strong></summary><blockquote><p>Время обновления: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Определение Prompt инициализации</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/cli.ts#L13-L163" target="_blank" rel="noreferrer"><code>src/cli.ts</code></a></td><td>13-163</td></tr><tr><td>Реализация инструмента памяти</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L183-L485" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>183-485</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>SUPERMEMORY_INIT_COMMAND</code>: Определяет конкретное содержимое Prompt команды <code>/supermemory-init</code>, указывая Agent, как проводить исследования и запоминать.</li></ul></details>`,50)])])}const g=e(i,[["render",r]]);export{u as __pageData,g as default};
